25	  // reducer accumulates base and insurance separately — avoids 25 * 1.1 + 25 * 1.1
26	  // producing 60.00000000000001 for the two-rune case.
27	  const itemsTotal = items.reduce((sum, item) => {
28	    const base = BASE_PREMIUMS[item.type];
29	    return sum + base + base * FIRST_INSURANCE_RATE;
30	  }, 0);
31	  return itemsTotal + PROCESSING_FEE;
32	}
