const COMPONENT_BLOCK_BASE = 60;

export function quote(_customer: Customer, items: Item[]): number {
  // Kept as `base + base * rate` (rather than `base * (1 + rate)`) so the
  // reducer accumulates base and insurance separately — avoids 25 * 1.1 + 25 * 1.1
  // producing 60.00000000000001 for the two-rune case.
  const baseSum = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  // A block of exactly 3 alike runes replaces 3×25 = 75 with 60.
  const runeCount = items.filter((item) => item.type === "rune").length;
  const blockAdjustment = runeCount === 3 ? COMPONENT_BLOCK_BASE - 3 * BASE_PREMIUMS.rune : 0;
  const adjustedBase = baseSum + blockAdjustment;
  const itemsTotal = adjustedBase + adjustedBase * FIRST_INSURANCE_RATE;
  return itemsTotal + PROCESSING_FEE;
}

